  ('aboriginal-6f0ba476-moex-00081', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依我國現行稅法規定，下列何種情形免徵契稅？', '["建築物於建造完成前，其興建中之建築工程讓與他人繼續建造未完工部分，因而變更起造人名 義為受讓人，並以該受讓人為起造人名義取得使用執照者", "以不動產為信託財產，受託人依信託本旨移轉信託財產與委託人以外之歸屬權利人者", "向法院標購拍賣之不動產者", "共有人分割不動產"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
