  ('aboriginal-6f0ba476-moex-00084', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '有關柏瑞圖最適與柏瑞圖改善之比較，下列敘述何者正確？', '["柏瑞圖改善係指無法在不損及其他個體福利下，提高部分個體福利", "生產可能曲線區域內的點均為柏瑞圖最適", "若不存在柏瑞圖改善空間，代表經濟狀態已達柏瑞圖最適", "由一個柏瑞圖最適狀態移至另一個柏瑞圖最適狀態，即完成柏瑞圖改善"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "b28b3900a079", "answer_pdf_sha1": "9b82f5c99ee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00085', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '假設社會上僅有甲與乙二人，且其對某一財貨的個人需求曲線分別為甲：P+Q=100；乙：P+2Q=100， 此財貨的市場為完全競爭，其中P為價格，Q為數量。下列敘述何者正確？', '["若此財貨為公共財，則當財貨的提供成本為40時，社會最適數量為60單位", "若此財貨為公共財，則當社會最適數量為40單位時，甲、乙的邊際利益分別為60元、20元", "若此財貨為私有財，則當社會最適數量為40單位時，甲、乙的價格分別為60元、20元", "若此財貨為私有財，則當財貨的提供成本為40時，社會最適數量為60單位"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "b28b3900a079", "answer_pdf_sha1": "9b82f5c99ee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00086', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-f6c431ec', 'sub-aboriginal-6f0ba476-04', NULL, 'single_choice', '假設橘子為完全競爭市場，種植橘子時噴灑農藥會產生污染，邊際外部成本為2元，橘子需求函 數為Qd=500-100P，供給函數為Qs=-300+100P，在未受管制的情形下，市場均衡時的社會總外部 成本為多少元？', '["2元", "100元", "200元", "400元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "b28b3900a079", "answer_pdf_sha1": "9b82f5c99ee2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
